# Integrating Claude into Your Next.js App

The simplest approach is **API routes + streaming**. Here's the minimal setup:

## 1. Install the SDK

```bash
npm install @anthropic-ai/sdk
```

## 2. Create an API Route

Create `app/api/chat/route.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { NextRequest } from "next/server";

const client = new Anthropic();

export async function POST(req: NextRequest) {
  const { messages } = await req.json();

  const stream = await client.messages.create({
    model: "claude-opus-4-6",
    max_tokens: 1024,
    messages: messages,
    stream: true,
  });

  // Convert Anthropic's async iterable to ReadableStream
  const readable = new ReadableStream({
    async start(controller) {
      for await (const event of stream) {
        // Send raw SSE format for browser compatibility
        if (
          event.type === "content_block_delta" &&
          event.delta.type === "text_delta"
        ) {
          controller.enqueue(
            `data: ${JSON.stringify({ text: event.delta.text })}\n\n`
          );
        }
      }
      controller.close();
    },
  });

  return new Response(readable, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

## 3. Add Client-Side Hook

Create `lib/useChat.ts`:

```typescript
import { useCallback, useState } from "react";

interface Message {
  role: "user" | "assistant";
  content: string;
}

export function useChat() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const sendMessage = useCallback(
    async (userMessage: string) => {
      setIsLoading(true);
      setMessages((prev) => [
        ...prev,
        { role: "user", content: userMessage },
      ]);

      let assistantResponse = "";

      try {
        const response = await fetch("/api/chat", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            messages: [...messages, { role: "user", content: userMessage }],
          }),
        });

        const reader = response.body?.getReader();
        if (!reader) throw new Error("No response body");

        const decoder = new TextDecoder();

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value);
          const lines = chunk.split("\n");

          for (const line of lines) {
            if (line.startsWith("data: ")) {
              const data = JSON.parse(line.slice(6));
              assistantResponse += data.text;
              setMessages((prev) => {
                const newMessages = [...prev];
                newMessages[newMessages.length - 1] = {
                  role: "assistant",
                  content: assistantResponse,
                };
                return newMessages;
              });
            }
          }
        }
      } catch (error) {
        console.error("Chat error:", error);
      } finally {
        setIsLoading(false);
      }
    },
    [messages]
  );

  return { messages, sendMessage, isLoading };
}
```

